  let showItems = () => {
    return props.room.items.map((i, n) => {
      return (<Item name={props.i.name} item={i} n={n} turnOnOrOff={props.turnOnOrOff} />)
    })
  }
  let addItem = () => {
    if (newItemName.length > 1) {
      props.addNewDeco(props.name, newItemName)
    }
    else
      window.alert("invalid name product wasnt saved");

  }

  return (
    <div>
      <h2>Edit the Room</h2>
      <h3>Room-Name: {props.room.name}</h3>
      <h3>Room-Type: {props.room.roomType}</h3>
      <h3>Current items list:</h3>
